import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mic, Loader, X, Wand2, Sparkles } from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { ParsedHabit } from '../types';

declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  start: () => void;
  stop: () => void;
  abort: () => void;
  onresult: (event: any) => void;
  onend: () => void;
  onerror: (event: any) => void;
}

interface VoiceModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (habits: ParsedHabit[]) => void;
}

export const VoiceModal: React.FC<VoiceModalProps> = ({ isOpen, onClose, onConfirm }) => {
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [transcript, setTranscript] = useState('');
  const recognitionRef = useRef<SpeechRecognition | null>(null);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();

      if (recognitionRef.current) {
        recognitionRef.current.continuous = false;
        recognitionRef.current.interimResults = true;

        recognitionRef.current.onresult = (event: any) => {
          let interimTranscript = '';
          for (let i = event.resultIndex; i < event.results.length; ++i) {
            interimTranscript += event.results[i][0].transcript;
          }
          setTranscript(interimTranscript);
        };

        recognitionRef.current.onend = () => {
          setIsListening(false);
        };

        recognitionRef.current.onerror = (event: any) => {
            console.error(event.error);
            setIsListening(false);
        };
      }
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setTranscript('');
      recognitionRef.current?.start();
      setIsListening(true);
    }
  };

  const handleProcess = async () => {
    if (!transcript) return;
    setIsProcessing(true);
    try {
      const habits = await GeminiService.parseHabitsFromText(transcript);
      if (habits.length > 0) {
          onConfirm(habits);
          onClose();
          setTranscript('');
      } else {
          alert("Could not understand habits from that text. Try 'Daily meditate for 10 mins'.");
      }
    } catch (error) {
      console.error(error);
      alert("Failed to process with AI. Check console or API key.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          {/* Backdrop */}
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/80 backdrop-blur-xl"
            onClick={onClose}
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="w-full max-w-md bg-[#09090b] border border-white/10 rounded-3xl shadow-2xl relative z-10 overflow-hidden"
          >
            {/* Header */}
            <div className="p-6 flex justify-between items-center border-b border-white/5">
                <div className="flex items-center gap-2 text-white">
                   <Sparkles size={18} />
                   <h3 className="font-medium tracking-wide">Voice Input</h3>
                </div>
                <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors">
                  <X size={20} />
                </button>
            </div>

            <div className="p-8 flex flex-col items-center">
              <div className="min-h-[100px] w-full text-center mb-10 flex items-center justify-center">
                {transcript ? (
                  <p className="text-white text-xl font-light leading-relaxed">"{transcript}"</p>
                ) : (
                  <p className="text-zinc-600 font-light">
                    Try saying: <br/>
                    <span className="text-zinc-500 italic">"Read a book, run 5k, and meditate weekly"</span>
                  </p>
                )}
              </div>

              <button
                onClick={toggleListening}
                className={`
                  relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-500
                  ${isListening 
                    ? 'bg-white text-black scale-110 shadow-[0_0_40px_rgba(255,255,255,0.2)]' 
                    : 'bg-zinc-900 border border-zinc-700 text-white hover:border-white hover:bg-zinc-800'}
                `}
              >
                <Mic size={32} strokeWidth={1.5} />
                {isListening && (
                    <span className="absolute inset-0 rounded-full border border-white animate-ping opacity-20"></span>
                )}
              </button>

              <p className="mt-6 text-xs text-zinc-500 uppercase tracking-widest font-medium">
                  {isListening ? 'Listening...' : 'Tap to Speak'}
              </p>
            </div>

            <div className="p-4 bg-zinc-900/50 border-t border-white/5">
               <button 
                onClick={handleProcess}
                disabled={!transcript || isProcessing}
                className="w-full bg-white text-black py-4 rounded-xl font-bold flex items-center justify-center gap-3 disabled:opacity-20 disabled:cursor-not-allowed hover:bg-zinc-200 transition-colors"
               >
                 {isProcessing ? <Loader className="animate-spin" size={20}/> : <Wand2 size={20} />}
                 {isProcessing ? 'Processing...' : 'Create Habits'}
               </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, LayoutDashboard, BarChart2, BookOpen, Mic, ChevronRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { loadState, saveState } from './services/storageService';
import { Habit, AppState, View, ParsedHabit } from './types';
import { HabitCard } from './components/HabitCard';
import { Analytics } from './components/Analytics';
import { Reflections } from './components/Reflections';
import { VoiceModal } from './components/VoiceModal';

// Quotes
const QUOTES = [
  "Simplicity is the ultimate sophistication.",
  "Focus on the essential.",
  "Discipline is freedom.",
  "Less, but better.",
  "Consistency beats intensity."
];

export default function App() {
  const [state, setState] = useState<AppState>({ habits: [], reflections: [] });
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [activeTab, setActiveTab] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  const [isVoiceModalOpen, setIsVoiceModalOpen] = useState(false);
  const [quote, setQuote] = useState(QUOTES[0]);

  useEffect(() => {
    const loaded = loadState();
    setState(loaded);
    setQuote(QUOTES[Math.floor(Math.random() * QUOTES.length)]);
  }, []);

  useEffect(() => {
    if (state.habits.length > 0 || state.reflections.length > 0) {
      saveState(state);
    }
  }, [state]);

  const today = new Date();
  const dateKey = today.toISOString().split('T')[0]; // YYYY-MM-DD
  const currentMonthKey = dateKey.slice(0, 7); // YYYY-MM

  const getWeekKey = (date: Date) => {
    const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
    const dayNum = d.getUTCDay() || 7;
    d.setUTCDate(d.getUTCDate() + 4 - dayNum);
    const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
    const weekNo = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
    return `${d.getUTCFullYear()}-W${weekNo}`;
  };
  const weekKey = getWeekKey(today);

  const getKeyForFrequency = (freq: 'daily' | 'weekly' | 'monthly') => {
      if (freq === 'daily') return dateKey;
      if (freq === 'weekly') return weekKey;
      return currentMonthKey;
  };

  const handleToggleHabit = (id: string, key: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => {
        if (h.id === id) {
          const newHistory = { ...h.history };
          if (newHistory[key]) {
            delete newHistory[key];
          } else {
            newHistory[key] = true;
          }
          return { ...h, history: newHistory };
        }
        return h;
      })
    }));
  };

  const handleDeleteHabit = (id: string) => {
    if (confirm("Delete this habit?")) {
        setState(prev => ({
            ...prev,
            habits: prev.habits.filter(h => h.id !== id)
        }));
    }
  };

  const handleAddHabitsFromAI = (parsedHabits: ParsedHabit[]) => {
    const newHabits: Habit[] = parsedHabits.map(ph => ({
      id: crypto.randomUUID(),
      title: ph.title,
      frequency: ph.frequency,
      createdAt: new Date().toISOString(),
      history: {}
    }));

    setState(prev => ({
      ...prev,
      habits: [...prev.habits, ...newHabits]
    }));
  };

  const handleSaveReflection = (reflection: any) => {
      setState(prev => {
          const others = prev.reflections.filter(r => r.month !== reflection.month);
          return {
              ...prev,
              reflections: [...others, reflection]
          };
      });
  };

  const dailyHabits = state.habits.filter(h => h.frequency === 'daily');
  const dailyCompleted = dailyHabits.filter(h => h.history[dateKey]).length;
  const dailyTotal = dailyHabits.length;
  const progressPercent = dailyTotal === 0 ? 0 : Math.round((dailyCompleted / dailyTotal) * 100);
  const circumference = 2 * Math.PI * 24; 
  const strokeDashoffset = circumference - (progressPercent / 100) * circumference;

  const displayedHabits = state.habits.filter(h => h.frequency === activeTab);

  return (
    <div className="min-h-screen text-zinc-200 pb-32">

      {/* Header - Transparent/Glass */}
      <header className="px-6 py-8 sticky top-0 z-30 bg-black/50 backdrop-blur-md border-b border-white/5">
        <div className="max-w-2xl mx-auto flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-white tracking-tight flex items-center gap-2">
              NeonFlow <span className="px-2 py-0.5 rounded text-[10px] bg-white text-black font-bold uppercase tracking-wider">Mono</span>
            </h1>
            <p className="text-xs text-zinc-500 font-mono mt-1 uppercase tracking-widest">{today.toDateString()}</p>
          </div>

          <div className="relative w-14 h-14 flex items-center justify-center group cursor-default">
            <svg className="w-full h-full transform -rotate-90">
              <circle cx="28" cy="28" r="24" stroke="#27272a" strokeWidth="2" fill="transparent" />
              <circle 
                cx="28" cy="28" r="24" 
                stroke="white" strokeWidth="2" 
                fill="transparent"
                strokeDasharray={circumference}
                strokeDashoffset={strokeDashoffset}
                strokeLinecap="round"
                className="transition-all duration-1000 ease-out"
              />
            </svg>
            <span className="absolute text-[10px] font-bold text-white">{progressPercent}%</span>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="px-4 mt-8 max-w-2xl mx-auto">

        {currentView === 'dashboard' && (
          <>
             {/* Quote */}
            <div className="mb-8 p-4 border border-white/5 rounded-xl bg-white/5 flex items-center justify-between">
                <p className="text-sm text-zinc-400 italic">"{quote}"</p>
                <div className="w-1 h-1 bg-white rounded-full"></div>
            </div>

            {/* Filter Tabs */}
            <div className="flex p-1 bg-zinc-900/80 border border-white/5 rounded-xl mb-8 sticky top-28 z-20 backdrop-blur-xl">
              {(['daily', 'weekly', 'monthly'] as const).map(tab => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={`flex-1 py-2.5 text-xs font-bold uppercase tracking-wider rounded-lg transition-all ${
                    activeTab === tab 
                      ? 'bg-white text-black shadow-lg' 
                      : 'text-zinc-500 hover:text-zinc-300'
                  }`}
                >
                  {tab}
                </button>
              ))}
            </div>

            {/* Habits */}
            <AnimatePresence mode="popLayout">
              {displayedHabits.length > 0 ? (
                displayedHabits.map(habit => (
                  <HabitCard 
                    key={habit.id} 
                    habit={habit} 
                    currentDateKey={getKeyForFrequency(habit.frequency)}
                    onToggle={handleToggleHabit} 
                    onDelete={handleDeleteHabit}
                  />
                ))
              ) : (
                <motion.div 
                  initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                  className="text-center py-20 border border-dashed border-zinc-800 rounded-2xl"
                >
                  <div className="w-12 h-12 bg-zinc-900 rounded-full flex items-center justify-center mx-auto mb-4 text-zinc-600">
                    <Plus size={20} />
                  </div>
                  <p className="text-zinc-500 text-sm">No {activeTab} habits yet.</p>
                </motion.div>
              )}
            </AnimatePresence>
          </>
        )}

        {currentView === 'analytics' && <Analytics habits={state.habits} />}

        {currentView === 'reflections' && (
          <Reflections 
            currentMonth={currentMonthKey} 
            savedReflections={state.reflections}
            onSave={handleSaveReflection}
          />
        )}

      </main>

      {/* Floating Action Button (Voice) */}
      <div className="fixed bottom-28 right-6 z-40">
        <button
          onClick={() => setIsVoiceModalOpen(true)}
          className="w-16 h-16 bg-white rounded-full shadow-[0_0_30px_rgba(255,255,255,0.15)] flex items-center justify-center text-black hover:scale-105 transition-transform active:scale-95 border-4 border-black"
        >
          <Mic size={24} />
        </button>
      </div>

      {/* Floating Navigation Dock */}
      <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 z-50 w-full max-w-sm px-4">
        <nav className="glass-nav rounded-2xl p-2 flex justify-between items-center shadow-2xl border border-white/10">
          <button 
            onClick={() => setCurrentView('dashboard')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'dashboard' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <LayoutDashboard size={20} strokeWidth={1.5} />
            <span className="text-[10px] font-medium tracking-wide">Track</span>
          </button>
          <div className="w-px h-8 bg-white/5"></div>
          <button 
            onClick={() => setCurrentView('analytics')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'analytics' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <BarChart2 size={20} strokeWidth={1.5} />
            <span className="text-[10px] font-medium tracking-wide">Stats</span>
          </button>
          <div className="w-px h-8 bg-white/5"></div>
          <button 
             onClick={() => setCurrentView('reflections')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'reflections' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <BookOpen size={20} strokeWidth={1.5} />
            <span className="text-[10px] font-medium tracking-wide">Review</span>
          </button>
        </nav>
      </div>

      <VoiceModal 
        isOpen={isVoiceModalOpen} 
        onClose={() => setIsVoiceModalOpen(false)} 
        onConfirm={handleAddHabitsFromAI}
      />

    </div>
  );
}

export type Frequency = 'daily' | 'weekly' | 'monthly';

export interface Habit {
  id: string;
  title: string;
  frequency: Frequency;
  createdAt: string; // ISO Date string
  history: Record<string, boolean>; // key: YYYY-MM-DD (or YYYY-Wx or YYYY-MM), value: completed
}

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  createdAt: string;
  isDeadlineRef?: boolean; // If true, this is a reference to a deadline
}

export interface Deadline {
  id: string;
  title: string;
  dueDate: string; // YYYY-MM-DD
  completed: boolean;
}

export interface Reflection {
  id: string;
  month: string; // YYYY-MM
  highlights: string;
  struggles: string;
  focusNext: string;
}

export interface AppState {
  habits: Habit[];
  tasks: Task[];
  deadlines: Deadline[];
  reflections: Reflection[];
}

export type View = 'dashboard' | 'todo' | 'deadlines' | 'analytics' | 'reflections';

// For Gemini Parsing
export interface ParsedHabit {
  title: string;
  frequency: Frequency;
}

import { AppState, Habit, Reflection } from '../types';

const STORAGE_KEY = 'neonflow_data_v1';

const DEFAULT_STATE: AppState = {
  habits: [],
  tasks: [],
  deadlines: [],
  reflections: []
};

export const saveState = (state: AppState): void => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch (e) {
    console.error("Failed to save state", e);
  }
};

export const loadState = (): AppState => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : DEFAULT_STATE;
  } catch (e) {
    console.error("Failed to load state", e);
    return DEFAULT_STATE;
  }
};

export const clearState = (): void => {
  localStorage.removeItem(STORAGE_KEY);
};

import React, { useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Check, Flame, X, Edit2 } from 'lucide-react';
import { Habit } from '../types';

interface HabitCardProps {
  habit: Habit;
  currentDateKey: string; // YYYY-MM-DD, etc.
  onToggle: (id: string, dateKey: string) => void;
  onEdit: (habit: Habit) => void;
  onDelete: (id: string) => void;
}

const calculateStreak = (habit: Habit): number => {
  if (habit.frequency !== 'daily') return 0;

  let streak = 0;
  const today = new Date();

  for (let i = 0; i < 365; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const key = d.toISOString().split('T')[0];

    if (i === 0 && !habit.history[key]) continue;

    if (habit.history[key]) {
      streak++;
    } else {
      break;
    }
  }
  return streak;
};

export const HabitCard: React.FC<HabitCardProps> = ({ habit, currentDateKey, onToggle, onEdit, onDelete }) => {
  const isCompleted = !!habit.history[currentDateKey];
  const streak = useMemo(() => calculateStreak(habit), [habit.history, habit.frequency]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95 }}
      whileTap={{ scale: 0.99 }}
      className={`
        group relative overflow-hidden rounded-2xl p-5 mb-3 border transition-all duration-300
        ${isCompleted 
          ? 'bg-white/10 border-white/20 shadow-[0_0_20px_rgba(255,255,255,0.05)]' 
          : 'glass-card hover:bg-white/5'}
      `}
    >
      <div className="flex items-center justify-between z-10 relative">
        <div className="flex-1 cursor-pointer" onClick={() => onToggle(habit.id, currentDateKey)}>
          <h3 className={`font-medium text-lg transition-all duration-300 pr-16 ${isCompleted ? 'text-zinc-400 line-through' : 'text-white'}`}>
            {habit.title}
          </h3>
          <div className="flex items-center gap-3 mt-1 text-xs">
             <span className="capitalize px-2 py-0.5 rounded-full bg-white/5 border border-white/10 text-zinc-400">
               {habit.frequency}
             </span>
             {habit.frequency === 'daily' && streak > 0 && (
               <span className="flex items-center gap-1 text-white/80">
                 <Flame size={12} className="fill-white" /> {streak} day streak
               </span>
             )}
          </div>
        </div>

        <button
          onClick={(e) => { e.stopPropagation(); onToggle(habit.id, currentDateKey); }}
          className={`
            w-10 h-10 rounded-full flex items-center justify-center border transition-all duration-300
            ${isCompleted 
              ? 'bg-white text-black border-white scale-110' 
              : 'bg-transparent border-zinc-600 text-zinc-600 hover:border-white hover:text-white'}
          `}
        >
           <AnimatePresence mode='wait'>
             {isCompleted && (
               <motion.div
                 initial={{ scale: 0 }}
                 animate={{ scale: 1 }}
                 exit={{ scale: 0 }}
               >
                 <Check size={20} strokeWidth={4} />
               </motion.div>
             )}
           </AnimatePresence>
        </button>
      </div>

      {/* Background fill animation for completion */}
      <div className={`absolute inset-0 bg-gradient-to-r from-white/5 to-transparent transition-opacity duration-500 pointer-events-none ${isCompleted ? 'opacity-100' : 'opacity-0'}`} />

      {/* Action Buttons - Always visible but subtle */}
      <div className="absolute top-2 right-2 flex gap-1">
         <button 
           onClick={(e) => { e.stopPropagation(); onEdit(habit); }} 
           className="text-zinc-600 hover:text-white p-2 rounded-full hover:bg-white/10 transition-colors"
           title="Edit"
         >
            <Edit2 size={14} />
         </button>
         <button 
           onClick={(e) => { e.stopPropagation(); onDelete(habit.id); }} 
           className="text-zinc-600 hover:text-red-400 p-2 rounded-full hover:bg-white/10 transition-colors"
           title="Delete"
         >
            <X size={14} />
         </button>
      </div>
    </motion.div>
  );
};

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X } from 'lucide-react';
import { Habit, Frequency } from '../types';

interface ManualHabitModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (title: string, frequency: Frequency, id?: string) => void;
  editHabit?: Habit | null;
}

export const ManualHabitModal: React.FC<ManualHabitModalProps> = ({ isOpen, onClose, onSave, editHabit }) => {
