import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Trash2, Calendar, CheckCircle2, Circle } from 'lucide-react';
import { Task } from '../types';

interface TodoViewProps {
  tasks: Task[];
  onAddTask: (title: string) => void;
  onToggleTask: (id: string) => void;
  onDeleteTask: (id: string) => void;
}

export const TodoView: React.FC<TodoViewProps> = ({ tasks, onAddTask, onToggleTask, onDeleteTask }) => {
  const [newTask, setNewTask] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTask.trim()) return;
    onAddTask(newTask);
    setNewTask('');
  };

  const today = new Date();
  const dateString = today.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

  // Separate tasks into pending and completed
  const pendingTasks = tasks.filter(t => !t.completed);
  const completedTasks = tasks.filter(t => t.completed);

  return (
    <div className="pb-24">
      {/* Calendar Strip / Header */}
      <div className="mb-6 glass-panel p-4 rounded-xl flex items-center gap-3">
        <div className="bg-white/10 p-2 rounded-lg">
          <Calendar size={20} className="text-white" />
        </div>
        <div>
          <h2 className="text-sm font-bold text-white uppercase tracking-wide">Today's Focus</h2>
          <p className="text-xs text-zinc-400">{dateString}</p>
        </div>
      </div>

      {/* Add Task Input */}
      <form onSubmit={handleSubmit} className="relative mb-8">
        <input
          type="text"
          value={newTask}
          onChange={(e) => setNewTask(e.target.value)}
          placeholder="Add a new task..."
          className="w-full bg-zinc-900 border border-white/10 rounded-xl p-4 pr-12 text-white placeholder:text-zinc-600 focus:border-white/30 outline-none transition-all"
        />
        <button 
          type="submit"
          disabled={!newTask.trim()}
          className="absolute right-2 top-2 p-2 bg-white text-black rounded-lg disabled:opacity-0 transition-all hover:bg-zinc-200"
        >
          <Plus size={18} />
        </button>
      </form>

      {/* Tasks List */}
      <div className="space-y-3">
        <AnimatePresence mode="popLayout">
          {pendingTasks.map(task => (
            <motion.div
              key={task.id}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className={`glass-card p-4 rounded-xl flex items-center gap-3 group ${task.isDeadlineRef ? 'border-l-2 border-l-red-500' : ''}`}
            >
              <button 
                onClick={() => onToggleTask(task.id)}
                className="text-zinc-500 hover:text-white transition-colors"
              >
                <Circle size={22} strokeWidth={1.5} />
              </button>
              <span className="flex-1 text-white font-medium">{task.title}</span>
              {task.isDeadlineRef && <span className="text-[10px] bg-red-500/20 text-red-200 px-2 py-0.5 rounded uppercase tracking-wider">Due Soon</span>}
              <button 
                onClick={() => onDeleteTask(task.id)}
                className="opacity-0 group-hover:opacity-100 text-zinc-600 hover:text-red-400 transition-all"
              >
                <Trash2 size={16} />
              </button>
            </motion.div>
          ))}

          {completedTasks.length > 0 && (
            <div className="pt-4">
              <h3 className="text-xs font-bold text-zinc-600 uppercase tracking-widest mb-3">Completed</h3>
              {completedTasks.map(task => (
                 <motion.div
                  key={task.id}
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 0.5 }}
                  className="p-3 rounded-xl flex items-center gap-3 border border-transparent"
                >
                  <button onClick={() => onToggleTask(task.id)} className="text-zinc-500">
                    <CheckCircle2 size={22} className="text-zinc-600" />
                  </button>
                  <span className="flex-1 text-zinc-600 line-through decoration-zinc-700">{task.title}</span>
                  <button onClick={() => onDeleteTask(task.id)} className="text-zinc-700 hover:text-red-900">
                    <Trash2 size={16} />
                  </button>
                </motion.div>
              ))}
            </div>
          )}
        </AnimatePresence>

        {tasks.length === 0 && (
           <div className="text-center py-12">
              <p className="text-zinc-600 text-sm">No tasks for today.</p>
           </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Plus, Trash2, Clock, CheckCircle2, AlertCircle } from 'lucide-react';
import { Deadline } from '../types';

interface DeadlineViewProps {
  deadlines: Deadline[];
  onAddDeadline: (title: string, date: string) => void;
  onToggleDeadline: (id: string) => void;
  onDeleteDeadline: (id: string) => void;
}

const getDaysLeft = (dateStr: string) => {
  const today = new Date();
  today.setHours(0,0,0,0);
  const due = new Date(dateStr);
  due.setHours(0,0,0,0);
  const diffTime = due.getTime() - today.getTime();
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

export const DeadlineView: React.FC<DeadlineViewProps> = ({ deadlines, onAddDeadline, onToggleDeadline, onDeleteDeadline }) => {
  const [title, setTitle] = useState('');
  const [date, setDate] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !date) return;
    onAddDeadline(title, date);
    setTitle('');
    setDate('');
  };

  // Sort deadlines: Pending first (sorted by date), then Completed
  const sortedDeadlines = [...deadlines].sort((a, b) => {
    if (a.completed === b.completed) {
      return new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime();
    }
    return a.completed ? 1 : -1;
  });

  return (
    <div className="pb-24">
       {/* Header */}
       <div className="mb-6 glass-panel p-4 rounded-xl flex items-center gap-3">
        <div className="bg-white/10 p-2 rounded-lg">
          <Clock size={20} className="text-white" />
        </div>
        <div>
          <h2 className="text-sm font-bold text-white uppercase tracking-wide">Deadlines</h2>
          <p className="text-xs text-zinc-400">Track milestones & dates</p>
        </div>
      </div>

      {/* Add Deadline Form */}
      <form onSubmit={handleSubmit} className="mb-8 space-y-3">
        <input
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          placeholder="Deadline Title..."
          className="w-full bg-zinc-900 border border-white/10 rounded-xl p-4 text-white placeholder:text-zinc-600 focus:border-white/30 outline-none"
        />
        <div className="flex gap-2">
           <input
            type="date"
            value={date}
            onChange={(e) => setDate(e.target.value)}
            className="flex-1 bg-zinc-900 border border-white/10 rounded-xl p-4 text-white focus:border-white/30 outline-none"
           />
           <button 
            type="submit"
            disabled={!title.trim() || !date}
            className="bg-white text-black px-6 rounded-xl font-bold disabled:opacity-50 hover:bg-zinc-200 transition-colors"
           >
             <Plus size={20} />
           </button>
        </div>
      </form>

      {/* Deadlines List */}
      <div className="space-y-4">
         <AnimatePresence mode="popLayout">
           {sortedDeadlines.map(item => {
             const daysLeft = getDaysLeft(item.dueDate);
             const isOverdue = daysLeft < 0 && !item.completed;

             return (
               <motion.div
                 key={item.id}
                 layout
                 initial={{ opacity: 0, scale: 0.95 }}
                 animate={{ opacity: 1, scale: 1 }}
                 exit={{ opacity: 0, scale: 0.95 }}
                 className={`
                    p-5 rounded-2xl border transition-all
                    ${item.completed 
                        ? 'bg-zinc-900/50 border-transparent opacity-60' 
                        : isOverdue
                            ? 'bg-red-900/10 border-red-500/30'
                            : 'glass-card'
                    }
                 `}
               >
                 <div className="flex justify-between items-start mb-3">
                   <div className="flex items-start gap-3">
                     <button 
                        onClick={() => onToggleDeadline(item.id)}
                        className={`mt-1 ${item.completed ? 'text-zinc-500' : 'text-zinc-400 hover:text-white'}`}
                     >
                       {item.completed ? <CheckCircle2 size={20} /> : <div className="w-5 h-5 rounded-full border border-zinc-500"></div>}
                     </button>
                     <div>
                       <h3 className={`font-medium text-lg ${item.completed ? 'text-zinc-500 line-through' : 'text-white'}`}>{item.title}</h3>
                       <p className={`text-xs ${isOverdue ? 'text-red-400 font-bold' : 'text-zinc-500'}`}>
                         {new Date(item.dueDate).toLocaleDateString()} 
                         {!item.completed && (isOverdue ? ` • ${Math.abs(daysLeft)} days overdue` : ` • ${daysLeft} days left`)}
                       </p>
                     </div>
                   </div>
                   <button onClick={() => onDeleteDeadline(item.id)} className="text-zinc-600 hover:text-red-400">
                     <Trash2 size={16} />
                   </button>
                 </div>

                 {/* Visual Dots Indicator */}
                 {!item.completed && (
                   <div className="flex items-center gap-1.5 pl-8 mt-2">
                      {isOverdue ? (
                          <div className="flex items-center gap-2 text-red-500 text-xs font-bold uppercase tracking-widest">
                              <AlertCircle size={14} /> Overdue
                          </div>
                      ) : daysLeft === 0 ? (
                          <span className="text-yellow-500 text-xs font-bold uppercase tracking-widest">Due Today</span>
                      ) : (
                          // Show up to 14 dots
                          Array.from({ length: Math.min(daysLeft, 14) }).map((_, i) => (
                             <motion.div
                                key={i}
                                initial={{ opacity: 0, scale: 0 }}
                                animate={{ opacity: 1, scale: 1 }}
                                transition={{ delay: i * 0.05 }}
                                className={`rounded-full ${i < 3 ? 'w-2 h-2 bg-white' : 'w-1.5 h-1.5 bg-zinc-600'}`}
                             />
                          ))
                      )}
                      {daysLeft > 14 && <span className="text-zinc-600 text-xs">+ more</span>}
                   </div>
                 )}
               </motion.div>
             );
           })}
         </AnimatePresence>

         {deadlines.length === 0 && (
             <div className="text-center py-12">
               <p className="text-zinc-600 text-sm">No deadlines set.</p>
             </div>
         )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, LayoutDashboard, BarChart2, BookOpen, Mic, CheckSquare, Clock } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { loadState, saveState } from './services/storageService';
import { Habit, AppState, View, ParsedHabit, Frequency, Task } from './types';
import { HabitCard } from './components/HabitCard';
import { Analytics } from './components/Analytics';
import { Reflections } from './components/Reflections';
import { VoiceModal } from './components/VoiceModal';
import { ManualHabitModal } from './components/ManualHabitModal';
import { TodoView } from './components/TodoView';
import { DeadlineView } from './components/DeadlineView';

const QUOTES = [
  "Simplicity is the ultimate sophistication.",
  "Focus on the essential.",
  "Discipline is freedom.",
  "Less, but better.",
  "Consistency beats intensity."
];

export default function App() {
  const [state, setState] = useState<AppState>({ habits: [], tasks: [], deadlines: [], reflections: [] });
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [activeTab, setActiveTab] = useState<Frequency>('daily');
  const [isVoiceModalOpen, setIsVoiceModalOpen] = useState(false);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [editingHabit, setEditingHabit] = useState<Habit | null>(null);
  const [quote, setQuote] = useState(QUOTES[0]);

  useEffect(() => {
    const loaded = loadState();
    // Ensure new arrays exist if loading old state
    if (!loaded.tasks) loaded.tasks = [];
    if (!loaded.deadlines) loaded.deadlines = [];
    setState(loaded);
    setQuote(QUOTES[Math.floor(Math.random() * QUOTES.length)]);
  }, []);

  useEffect(() => {
    // Basic Sync Logic: Check deadlines due within 3 days and ensure they exist in Tasks
    // This is a simple one-way sync to populate the Todo list
    const today = new Date();
    today.setHours(0,0,0,0);

    const upcomingDeadlines = state.deadlines.filter(d => {
        if (d.completed) return false;
        const due = new Date(d.dueDate);
        due.setHours(0,0,0,0);
        const diffDays = (due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);
        return diffDays >= 0 && diffDays <= 3;
    });

    let newTasks = [...state.tasks];
    let changed = false;

    upcomingDeadlines.forEach(d => {
        const taskTitle = `Deadline: ${d.title}`;
        const exists = newTasks.some(t => t.title === taskTitle);
        if (!exists) {
            newTasks.push({
                id: crypto.randomUUID(),
                title: taskTitle,
                completed: false,
                createdAt: new Date().toISOString(),
                isDeadlineRef: true
            });
            changed = true;
        }
    });

    if (changed) {
        setState(prev => ({ ...prev, tasks: newTasks }));
        // Don't save immediately here to avoid loop, allow the next effect to catch it
    }
  }, [state.deadlines]); // Only run when deadlines change (or if we want to run daily, we need a smarter trigger)

  useEffect(() => {
    saveState(state);
  }, [state]);

  const today = new Date();
  const dateKey = today.toISOString().split('T')[0];
  const currentMonthKey = dateKey.slice(0, 7);

  const getWeekKey = (date: Date) => {
    const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
    const dayNum = d.getUTCDay() || 7;
    d.setUTCDate(d.getUTCDate() + 4 - dayNum);
    const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
    const weekNo = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
    return `${d.getUTCFullYear()}-W${weekNo}`;
  };
  const weekKey = getWeekKey(today);

  const getKeyForFrequency = (freq: Frequency) => {
      if (freq === 'daily') return dateKey;
      if (freq === 'weekly') return weekKey;
      return currentMonthKey;
  };

  // --- HABIT ACTIONS ---
  const handleToggleHabit = (id: string, key: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => {
        if (h.id === id) {
          const newHistory = { ...h.history };
          if (newHistory[key]) delete newHistory[key];
          else newHistory[key] = true;
          return { ...h, history: newHistory };
        }
        return h;
      })
    }));
  };

  const handleDeleteHabit = (id: string) => {
    if (confirm("Delete this habit?")) {
        setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }));
    }
  };

  const handleOpenEditHabit = (habit: Habit) => {
    setEditingHabit(habit);
    setIsManualModalOpen(true);
  };

  const handleSaveManualHabit = (title: string, frequency: Frequency, id?: string) => {
    if (id) {
      // Edit
      setState(prev => ({
        ...prev,
        habits: prev.habits.map(h => h.id === id ? { ...h, title, frequency } : h)
      }));
    } else {
      // Create
      const newHabit: Habit = {
        id: crypto.randomUUID(),
        title,
        frequency,
        createdAt: new Date().toISOString(),
        history: {}
      };
      setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
    }
  };

  const handleAddHabitsFromAI = (parsedHabits: ParsedHabit[]) => {
    const newHabits: Habit[] = parsedHabits.map(ph => ({
      id: crypto.randomUUID(),
      title: ph.title,
      frequency: ph.frequency,
      createdAt: new Date().toISOString(),
      history: {}
    }));
    setState(prev => ({ ...prev, habits: [...prev.habits, ...newHabits] }));
  };

  // --- TASK ACTIONS ---
  const handleAddTask = (title: string) => {
      const newTask: Task = {
          id: crypto.randomUUID(),
          title,
          completed: false,
          createdAt: new Date().toISOString()
      };
      setState(prev => ({ ...prev, tasks: [...prev.tasks, newTask] }));
  };

  const handleToggleTask = (id: string) => {
      setState(prev => ({
          ...prev,
          tasks: prev.tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t)
      }));
  };

  const handleDeleteTask = (id: string) => {
      setState(prev => ({ ...prev, tasks: prev.tasks.filter(t => t.id !== id) }));
  };

  // --- DEADLINE ACTIONS ---
  const handleAddDeadline = (title: string, date: string) => {
      setState(prev => ({
          ...prev,
          deadlines: [...prev.deadlines, {
              id: crypto.randomUUID(),
              title,
              dueDate: date,
              completed: false
          }]
      }));
  };

  const handleToggleDeadline = (id: string) => {
      setState(prev => ({
          ...prev,
          deadlines: prev.deadlines.map(d => d.id === id ? { ...d, completed: !d.completed } : d)
      }));
  };

  const handleDeleteDeadline = (id: string) => {
      setState(prev => ({ ...prev, deadlines: prev.deadlines.filter(d => d.id !== id) }));
  };

  // --- REFLECTION ACTIONS ---
  const handleSaveReflection = (reflection: any) => {
      setState(prev => {
          const others = prev.reflections.filter(r => r.month !== reflection.month);
          return { ...prev, reflections: [...others, reflection] };
      });
  };

  const dailyHabits = state.habits.filter(h => h.frequency === 'daily');
  const dailyCompleted = dailyHabits.filter(h => h.history[dateKey]).length;
  const progressPercent = dailyHabits.length === 0 ? 0 : Math.round((dailyCompleted / dailyHabits.length) * 100);
  const circumference = 2 * Math.PI * 24; 
  const strokeDashoffset = circumference - (progressPercent / 100) * circumference;

  const displayedHabits = state.habits.filter(h => h.frequency === activeTab);

  return (
    <div className="min-h-screen text-zinc-200 pb-32">

      {/* Header */}
      <header className="px-6 py-8 sticky top-0 z-30 bg-black/50 backdrop-blur-md border-b border-white/5">
        <div className="max-w-2xl mx-auto flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-white tracking-tight flex items-center gap-2">
              NeonFlow <span className="px-2 py-0.5 rounded text-[10px] bg-white text-black font-bold uppercase tracking-wider">Mono</span>
            </h1>
            <p className="text-xs text-zinc-500 font-mono mt-1 uppercase tracking-widest">{today.toDateString()}</p>
          </div>

          <div className="flex items-center gap-4">
            {currentView === 'dashboard' && (
                <button 
                  onClick={() => { setEditingHabit(null); setIsManualModalOpen(true); }}
                  className="w-8 h-8 rounded-full border border-zinc-700 flex items-center justify-center hover:bg-white hover:text-black hover:border-white transition-all"
                >
                    <Plus size={16} />
                </button>
            )}

            <div className="relative w-12 h-12 flex items-center justify-center group cursor-default">
                <svg className="w-full h-full transform -rotate-90">
                <circle cx="24" cy="24" r="20" stroke="#27272a" strokeWidth="2" fill="transparent" />
                <circle 
                    cx="24" cy="24" r="20" 
                    stroke="white" strokeWidth="2" 
                    fill="transparent"
                    strokeDasharray={circumference}
                    strokeDashoffset={strokeDashoffset}
                    strokeLinecap="round"
                    className="transition-all duration-1000 ease-out"
                />
                </svg>
                <span className="absolute text-[9px] font-bold text-white">{progressPercent}%</span>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="px-4 mt-8 max-w-2xl mx-auto">

        {currentView === 'dashboard' && (
          <>
            {/* Quote */}
            <div className="mb-8 p-4 border border-white/5 rounded-xl bg-white/5 flex items-center justify-between">
                <p className="text-sm text-zinc-400 italic">"{quote}"</p>
                <div className="w-1 h-1 bg-white rounded-full"></div>
            </div>

            {/* Filter Tabs */}
            <div className="flex p-1 bg-zinc-900/80 border border-white/5 rounded-xl mb-8 sticky top-28 z-20 backdrop-blur-xl">
              {(['daily', 'weekly', 'monthly'] as Frequency[]).map(tab => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={`flex-1 py-2.5 text-xs font-bold uppercase tracking-wider rounded-lg transition-all ${
                    activeTab === tab 
                      ? 'bg-white text-black shadow-lg' 
                      : 'text-zinc-500 hover:text-zinc-300'
                  }`}
                >
                  {tab}
                </button>
              ))}
            </div>

            {/* Habits */}
