export type Frequency = 'daily' | 'weekly' | 'monthly';

export interface Habit {
  id: string;
  title: string;
  frequency: Frequency;
  createdAt: string; // ISO Date string
  history: Record<string, boolean>; // key: YYYY-MM-DD (or YYYY-Wx or YYYY-MM), value: completed
}

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  createdAt: string;
  isDeadlineRef?: boolean; // If true, this is a reference to a deadline
}

export interface Deadline {
  id: string;
  title: string;
  dueDate: string; // YYYY-MM-DD
  completed: boolean;
}

export interface Reflection {
  id: string;
  month: string; // YYYY-MM
  highlights: string;
  struggles: string;
  focusNext: string;
}

export interface AppState {
  habits: Habit[];
  tasks: Task[];
  deadlines: Deadline[];
  reflections: Reflection[];
}

export type View = 'dashboard' | 'todo' | 'deadlines' | 'analytics' | 'reflections';

// For Gemini Parsing
export interface ParsedResponse {
  habits: { title: string; frequency: Frequency }[];
  todos: { title: string }[];
  deadlines: { title: string; dueDate: string }[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { ParsedResponse } from "../types";

const parseInputFromText = async (text: string): Promise<ParsedResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }

  const ai = new GoogleGenAI({ apiKey });
  const today = new Date();
  const dateString = today.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  const systemInstruction = `
    You are an intelligent personal productivity assistant. 
    Analyze the user's natural language input and categorize it into Habits, To-Dos, and Deadlines.

    Current Date: ${dateString} (Use this to calculate dates for deadlines like "next Friday").

    CATEGORIES:
    1. HABITS: Recurring actions (e.g., "Run daily", "Read weekly", "Meditate"). 
       - Default frequency is 'daily' if not specified.
    2. TODOS: One-off tasks for today or generally (e.g., "Buy milk", "Call Mom", "Finish report").
    3. DEADLINES: Tasks with a specific future date/time (e.g., "Project due on Friday", "Submit taxes by April 15th").
       - 'dueDate' must be in YYYY-MM-DD format.

    Return a JSON object with three arrays: 'habits', 'todos', and 'deadlines'.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: text,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            habits: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] }
                },
                required: ["title", "frequency"]
              }
            },
            todos: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING }
                },
                required: ["title"]
              }
            },
            deadlines: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  dueDate: { type: Type.STRING }
                },
                required: ["title", "dueDate"]
              }
            }
          },
          required: ["habits", "todos", "deadlines"]
        }
      }
    });

    const jsonText = response.text;
    if (!jsonText) return { habits: [], todos: [], deadlines: [] };

    return JSON.parse(jsonText) as ParsedResponse;
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return { habits: [], todos: [], deadlines: [] };
  }
};

export const GeminiService = {
  parseInputFromText
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mic, Loader, X, Wand2, Sparkles, Square } from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { ParsedResponse } from '../types';

declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  start: () => void;
  stop: () => void;
  abort: () => void;
  onresult: (event: any) => void;
  onend: () => void;
  onerror: (event: any) => void;
}

interface VoiceModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (data: ParsedResponse) => void;
}

export const VoiceModal: React.FC<VoiceModalProps> = ({ isOpen, onClose, onConfirm }) => {
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [transcript, setTranscript] = useState('');
  const recognitionRef = useRef<SpeechRecognition | null>(null);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();

      if (recognitionRef.current) {
        // Enable continuous to allow user to pause without stopping
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;

        recognitionRef.current.onresult = (event: any) => {
          let finalTranscript = '';
          for (let i = 0; i < event.results.length; ++i) {
            finalTranscript += event.results[i][0].transcript;
          }
          setTranscript(finalTranscript);
        };

        recognitionRef.current.onend = () => {
          setIsListening(false);
        };

        recognitionRef.current.onerror = (event: any) => {
            console.error("Speech Recognition Error:", event.error);
            if (event.error === 'no-speech' || event.error === 'network') {
               setIsListening(false);
            }
        };
      }
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
      setIsListening(false);
    } else {
      setTranscript('');
      recognitionRef.current?.start();
      setIsListening(true);
    }
  };

  const handleProcess = async () => {
    // Stop listening if still active
    if (isListening) {
        recognitionRef.current?.stop();
        setIsListening(false);
    }

    if (!transcript) return;
    setIsProcessing(true);
    try {
      const parsedData = await GeminiService.parseInputFromText(transcript);
      const hasContent = parsedData.habits.length > 0 || parsedData.todos.length > 0 || parsedData.deadlines.length > 0;

      if (hasContent) {
          onConfirm(parsedData);
          onClose();
          setTranscript('');
      } else {
          alert("Could not extract any items. Try saying 'Buy milk' or 'Run daily'.");
      }
    } catch (error) {
      console.error(error);
      alert("Failed to process with AI. Check console or API key.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          {/* Backdrop */}
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/80 backdrop-blur-xl"
            onClick={onClose}
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="w-full max-w-md bg-[#09090b] border border-white/10 rounded-3xl shadow-2xl relative z-10 overflow-hidden"
          >
            {/* Header */}
            <div className="p-6 flex justify-between items-center border-b border-white/5">
                <div className="flex items-center gap-2 text-white">
                   <Sparkles size={18} />
                   <h3 className="font-medium tracking-wide">Voice Assistant</h3>
                </div>
                <button onClick={onClose} className="text-zinc-500 hover:text-white transition-colors">
                  <X size={20} />
                </button>
            </div>

            <div className="p-8 flex flex-col items-center">
              <div className="min-h-[120px] max-h-[200px] overflow-y-auto w-full text-center mb-8 flex items-center justify-center">
                {transcript ? (
                  <p className="text-white text-xl font-light leading-relaxed">"{transcript}"</p>
                ) : (
                  <div className="space-y-2 text-zinc-600 font-light">
                    <p>Try saying:</p>
                    <p className="text-zinc-500 italic">"Remind me to call Mom tomorrow"</p>
                    <p className="text-zinc-500 italic">"Read a book weekly"</p>
                    <p className="text-zinc-500 italic">"Project deadline next Friday"</p>
                  </div>
                )}
              </div>

              <button
                onClick={toggleListening}
                className={`
                  relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300
                  ${isListening 
                    ? 'bg-red-500 text-white shadow-[0_0_40px_rgba(239,68,68,0.4)]' 
                    : 'bg-white text-black hover:bg-zinc-200'}
                `}
              >
                {isListening ? (
                    <Square size={24} fill="currentColor" />
                ) : (
                    <Mic size={32} strokeWidth={1.5} />
                )}

                {isListening && (
                    <span className="absolute inset-0 rounded-full border border-red-500 animate-ping opacity-40"></span>
                )}
              </button>

              <p className="mt-6 text-xs text-zinc-500 uppercase tracking-widest font-medium">
                  {isListening ? 'Tap to Stop' : 'Tap to Speak'}
              </p>
            </div>

            <div className="p-4 bg-zinc-900/50 border-t border-white/5">
               <button 
                onClick={handleProcess}
                disabled={!transcript || isProcessing}
                className="w-full bg-white text-black py-4 rounded-xl font-bold flex items-center justify-center gap-3 disabled:opacity-20 disabled:cursor-not-allowed hover:bg-zinc-200 transition-colors"
               >
                 {isProcessing ? <Loader className="animate-spin" size={20}/> : <Wand2 size={20} />}
                 {isProcessing ? 'Processing...' : 'Create Items'}
               </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

import React, { useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Check, Flame, X, Edit2 } from 'lucide-react';
import { Habit } from '../types';

interface HabitCardProps {
  habit: Habit;
  currentDateKey: string; // YYYY-MM-DD, etc.
  onToggle: (id: string, dateKey: string) => void;
  onEdit: (habit: Habit) => void;
  onDelete: (id: string) => void;
}

const calculateStreak = (habit: Habit): number => {
  if (habit.frequency !== 'daily') return 0;

  let streak = 0;
  const today = new Date();

  for (let i = 0; i < 365; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const key = d.toISOString().split('T')[0];

    if (i === 0 && !habit.history[key]) continue;

    if (habit.history[key]) {
      streak++;
    } else {
      break;
    }
  }
  return streak;
};

export const HabitCard: React.FC<HabitCardProps> = ({ habit, currentDateKey, onToggle, onEdit, onDelete }) => {
  const isCompleted = !!habit.history[currentDateKey];
  const streak = useMemo(() => calculateStreak(habit), [habit.history, habit.frequency]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95 }}
      whileTap={{ scale: 0.99 }}
      className={`
        group relative overflow-hidden rounded-2xl p-5 mb-3 border transition-all duration-300
        ${isCompleted 
          ? 'bg-white/10 border-white/20 shadow-[0_0_20px_rgba(255,255,255,0.05)]' 
          : 'glass-card hover:bg-white/5'}
      `}
    >
      <div className="flex items-center justify-between z-10 relative pointer-events-none">
        <div className="flex-1 cursor-pointer pointer-events-auto" onClick={() => onToggle(habit.id, currentDateKey)}>
          <h3 className={`font-medium text-lg transition-all duration-300 pr-16 ${isCompleted ? 'text-zinc-400 line-through' : 'text-white'}`}>
            {habit.title}
          </h3>
          <div className="flex items-center gap-3 mt-1 text-xs">
             <span className="capitalize px-2 py-0.5 rounded-full bg-white/5 border border-white/10 text-zinc-400">
               {habit.frequency}
             </span>
             {habit.frequency === 'daily' && streak > 0 && (
               <span className="flex items-center gap-1 text-white/80">
                 <Flame size={12} className="fill-white" /> {streak} day streak
               </span>
             )}
          </div>
        </div>

        <button
          onClick={(e) => { e.stopPropagation(); onToggle(habit.id, currentDateKey); }}
          className={`
            w-10 h-10 rounded-full flex items-center justify-center border transition-all duration-300 pointer-events-auto
            ${isCompleted 
              ? 'bg-white text-black border-white scale-110' 
              : 'bg-transparent border-zinc-600 text-zinc-600 hover:border-white hover:text-white'}
          `}
        >
           <AnimatePresence mode='wait'>
             {isCompleted && (
               <motion.div
                 initial={{ scale: 0 }}
                 animate={{ scale: 1 }}
                 exit={{ scale: 0 }}
               >
                 <Check size={20} strokeWidth={4} />
               </motion.div>
             )}
           </AnimatePresence>
        </button>
      </div>

      {/* Background fill animation for completion */}
      <div className={`absolute inset-0 bg-gradient-to-r from-white/5 to-transparent transition-opacity duration-500 pointer-events-none ${isCompleted ? 'opacity-100' : 'opacity-0'}`} />

      {/* Action Buttons - High z-index to ensure clickable */}
      <div className="absolute top-3 right-3 flex gap-2 z-20">
         <button 
           onClick={(e) => { e.stopPropagation(); onEdit(habit); }} 
           className="text-zinc-500 hover:text-white p-1.5 rounded-full hover:bg-white/10 transition-colors bg-black/20 backdrop-blur-sm"
           title="Edit"
         >
            <Edit2 size={14} />
         </button>
         <button 
           onClick={(e) => { e.stopPropagation(); onDelete(habit.id); }} 
           className="text-zinc-500 hover:text-red-400 p-1.5 rounded-full hover:bg-white/10 transition-colors bg-black/20 backdrop-blur-sm"
           title="Delete"
         >
            <X size={14} />
         </button>
      </div>
    </motion.div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, LayoutDashboard, BarChart2, BookOpen, Mic, CheckSquare, Clock } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { loadState, saveState } from './services/storageService';
import { Habit, AppState, View, ParsedResponse, Frequency, Task } from './types';
import { HabitCard } from './components/HabitCard';
import { Analytics } from './components/Analytics';
import { Reflections } from './components/Reflections';
import { VoiceModal } from './components/VoiceModal';
import { ManualHabitModal } from './components/ManualHabitModal';
import { TodoView } from './components/TodoView';
import { DeadlineView } from './components/DeadlineView';

const QUOTES = [
  "Simplicity is the ultimate sophistication.",
  "Focus on the essential.",
  "Discipline is freedom.",
  "Less, but better.",
  "Consistency beats intensity."
];

export default function App() {
  const [state, setState] = useState<AppState>({ habits: [], tasks: [], deadlines: [], reflections: [] });
  const [currentView, setCurrentView] = useState<View>('dashboard');
  const [activeTab, setActiveTab] = useState<Frequency>('daily');
  const [isVoiceModalOpen, setIsVoiceModalOpen] = useState(false);
  const [isManualModalOpen, setIsManualModalOpen] = useState(false);
  const [editingHabit, setEditingHabit] = useState<Habit | null>(null);
  const [quote, setQuote] = useState(QUOTES[0]);

  useEffect(() => {
    const loaded = loadState();
    if (!loaded.tasks) loaded.tasks = [];
    if (!loaded.deadlines) loaded.deadlines = [];
    setState(loaded);
    setQuote(QUOTES[Math.floor(Math.random() * QUOTES.length)]);
  }, []);

  // Sync Logic: Check deadlines due within 3 days
  useEffect(() => {
    const today = new Date();
    today.setHours(0,0,0,0);

    const upcomingDeadlines = state.deadlines.filter(d => {
        if (d.completed) return false;
        const due = new Date(d.dueDate);
        due.setHours(0,0,0,0);
        const diffDays = (due.getTime() - today.getTime()) / (1000 * 60 * 60 * 24);
        return diffDays >= 0 && diffDays <= 3;
    });

    let newTasks = [...state.tasks];
    let changed = false;

    upcomingDeadlines.forEach(d => {
        const taskTitle = `Deadline: ${d.title}`;
        const exists = newTasks.some(t => t.title === taskTitle);
        if (!exists) {
            newTasks.push({
                id: crypto.randomUUID(),
                title: taskTitle,
                completed: false,
                createdAt: new Date().toISOString(),
                isDeadlineRef: true
            });
            changed = true;
        }
    });

    if (changed) {
        setState(prev => ({ ...prev, tasks: newTasks }));
    }
  }, [state.deadlines]);

  useEffect(() => {
    saveState(state);
  }, [state]);

  const today = new Date();
  const dateKey = today.toISOString().split('T')[0];
  const currentMonthKey = dateKey.slice(0, 7);

  const getWeekKey = (date: Date) => {
    const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
    const dayNum = d.getUTCDay() || 7;
    d.setUTCDate(d.getUTCDate() + 4 - dayNum);
    const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
    const weekNo = Math.ceil((((d.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
    return `${d.getUTCFullYear()}-W${weekNo}`;
  };
  const weekKey = getWeekKey(today);

  const getKeyForFrequency = (freq: Frequency) => {
      if (freq === 'daily') return dateKey;
      if (freq === 'weekly') return weekKey;
      return currentMonthKey;
  };

  // --- ACTIONS ---

  const handleToggleHabit = (id: string, key: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => {
        if (h.id === id) {
          const newHistory = { ...h.history };
          if (newHistory[key]) delete newHistory[key];
          else newHistory[key] = true;
          return { ...h, history: newHistory };
        }
        return h;
      })
    }));
  };

  const handleDeleteHabit = (id: string) => {
    // Removed window.confirm or ensured it's not blocking awkwardly
    if (window.confirm("Are you sure you want to delete this habit?")) {
        setState(prev => ({ ...prev, habits: prev.habits.filter(h => h.id !== id) }));
    }
  };

  const handleOpenEditHabit = (habit: Habit) => {
    setEditingHabit(habit);
    setIsManualModalOpen(true);
  };

  const handleSaveManualHabit = (title: string, frequency: Frequency, id?: string) => {
    if (id) {
      setState(prev => ({
        ...prev,
        habits: prev.habits.map(h => h.id === id ? { ...h, title, frequency } : h)
      }));
    } else {
      const newHabit: Habit = {
        id: crypto.randomUUID(),
        title,
        frequency,
        createdAt: new Date().toISOString(),
        history: {}
      };
      setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
    }
  };

  const handleAIResponse = (parsedData: ParsedResponse) => {
    const newHabits = parsedData.habits.map(h => ({
        id: crypto.randomUUID(),
        title: h.title,
        frequency: h.frequency,
        createdAt: new Date().toISOString(),
        history: {}
    }));

    const newTasks = parsedData.todos.map(t => ({
        id: crypto.randomUUID(),
        title: t.title,
        completed: false,
        createdAt: new Date().toISOString()
    }));

    const newDeadlines = parsedData.deadlines.map(d => ({
        id: crypto.randomUUID(),
        title: d.title,
        dueDate: d.dueDate,
        completed: false
    }));

    setState(prev => ({
        ...prev,
        habits: [...prev.habits, ...newHabits],
        tasks: [...prev.tasks, ...newTasks],
        deadlines: [...prev.deadlines, ...newDeadlines]
    }));

    // Alert user what was added
    const count = newHabits.length + newTasks.length + newDeadlines.length;
    if (count > 0) {
        // Optional: toast notification here
        // For now, implicit success via UI update
        if (newTasks.length > 0) setCurrentView('todo');
        else if (newDeadlines.length > 0) setCurrentView('deadlines');
        else setCurrentView('dashboard');
    }
  };

  const handleAddTask = (title: string) => {
      const newTask: Task = {
          id: crypto.randomUUID(),
          title,
          completed: false,
          createdAt: new Date().toISOString()
      };
      setState(prev => ({ ...prev, tasks: [...prev.tasks, newTask] }));
  };

  const handleToggleTask = (id: string) => {
      setState(prev => ({
          ...prev,
          tasks: prev.tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t)
      }));
  };

  const handleDeleteTask = (id: string) => {
      setState(prev => ({ ...prev, tasks: prev.tasks.filter(t => t.id !== id) }));
  };

  const handleAddDeadline = (title: string, date: string) => {
      setState(prev => ({
          ...prev,
          deadlines: [...prev.deadlines, {
              id: crypto.randomUUID(),
              title,
              dueDate: date,
              completed: false
          }]
      }));
  };

  const handleToggleDeadline = (id: string) => {
      setState(prev => ({
          ...prev,
          deadlines: prev.deadlines.map(d => d.id === id ? { ...d, completed: !d.completed } : d)
      }));
  };

  const handleDeleteDeadline = (id: string) => {
      setState(prev => ({ ...prev, deadlines: prev.deadlines.filter(d => d.id !== id) }));
  };

  const handleSaveReflection = (reflection: any) => {
      setState(prev => {
          const others = prev.reflections.filter(r => r.month !== reflection.month);
          return { ...prev, reflections: [...others, reflection] };
      });
  };

  const dailyHabits = state.habits.filter(h => h.frequency === 'daily');
  const dailyCompleted = dailyHabits.filter(h => h.history[dateKey]).length;
  const progressPercent = dailyHabits.length === 0 ? 0 : Math.round((dailyCompleted / dailyHabits.length) * 100);
  const circumference = 2 * Math.PI * 24; 
  const strokeDashoffset = circumference - (progressPercent / 100) * circumference;

  const displayedHabits = state.habits.filter(h => h.frequency === activeTab);

  return (
    <div className="min-h-screen text-zinc-200 pb-32">

      {/* Header */}
      <header className="px-6 py-8 sticky top-0 z-30 bg-black/50 backdrop-blur-md border-b border-white/5">
        <div className="max-w-2xl mx-auto flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold text-white tracking-tight flex items-center gap-2">
              NeonFlow <span className="px-2 py-0.5 rounded text-[10px] bg-white text-black font-bold uppercase tracking-wider">Mono</span>
            </h1>
            <p className="text-xs text-zinc-500 font-mono mt-1 uppercase tracking-widest">{today.toDateString()}</p>
          </div>

          <div className="flex items-center gap-4">
            {currentView === 'dashboard' && (
                <button 
                  onClick={() => { setEditingHabit(null); setIsManualModalOpen(true); }}
                  className="w-8 h-8 rounded-full border border-zinc-700 flex items-center justify-center hover:bg-white hover:text-black hover:border-white transition-all"
                >
                    <Plus size={16} />
                </button>
            )}

            <div className="relative w-12 h-12 flex items-center justify-center group cursor-default">
                <svg className="w-full h-full transform -rotate-90">
                <circle cx="24" cy="24" r="20" stroke="#27272a" strokeWidth="2" fill="transparent" />
                <circle 
                    cx="24" cy="24" r="20" 
                    stroke="white" strokeWidth="2" 
                    fill="transparent"
                    strokeDasharray={circumference}
                    strokeDashoffset={strokeDashoffset}
                    strokeLinecap="round"
                    className="transition-all duration-1000 ease-out"
                />
                </svg>
                <span className="absolute text-[9px] font-bold text-white">{progressPercent}%</span>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="px-4 mt-8 max-w-2xl mx-auto">

        {currentView === 'dashboard' && (
          <>
            {/* Quote */}
            <div className="mb-8 p-4 border border-white/5 rounded-xl bg-white/5 flex items-center justify-between">
                <p className="text-sm text-zinc-400 italic">"{quote}"</p>
                <div className="w-1 h-1 bg-white rounded-full"></div>
            </div>

            {/* Filter Tabs */}
            <div className="flex p-1 bg-zinc-900/80 border border-white/5 rounded-xl mb-8 sticky top-28 z-20 backdrop-blur-xl">
              {(['daily', 'weekly', 'monthly'] as Frequency[]).map(tab => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={`flex-1 py-2.5 text-xs font-bold uppercase tracking-wider rounded-lg transition-all ${
                    activeTab === tab 
                      ? 'bg-white text-black shadow-lg' 
                      : 'text-zinc-500 hover:text-zinc-300'
                  }`}
                >
                  {tab}
                </button>
              ))}
            </div>

            {/* Habits */}
            <AnimatePresence mode="popLayout">
              {displayedHabits.length > 0 ? (
                displayedHabits.map(habit => (
                  <HabitCard 
                    key={habit.id} 
                    habit={habit} 
                    currentDateKey={getKeyForFrequency(habit.frequency)}
                    onToggle={handleToggleHabit} 
                    onEdit={handleOpenEditHabit}
                    onDelete={handleDeleteHabit}
