                ))
              ) : (
                <motion.div 
                  initial={{ opacity: 0 }} animate={{ opacity: 1 }}
                  className="text-center py-20 border border-dashed border-zinc-800 rounded-2xl"
                >
                  <div className="w-12 h-12 bg-zinc-900 rounded-full flex items-center justify-center mx-auto mb-4 text-zinc-600">
                    <Plus size={20} />
                  </div>
                  <p className="text-zinc-500 text-sm">No {activeTab} habits yet.</p>
                </motion.div>
              )}
            </AnimatePresence>
          </>
        )}

        {currentView === 'todo' && (
            <TodoView 
                tasks={state.tasks} 
                onAddTask={handleAddTask} 
                onToggleTask={handleToggleTask} 
                onDeleteTask={handleDeleteTask} 
            />
        )}

        {currentView === 'deadlines' && (
            <DeadlineView 
                deadlines={state.deadlines} 
                onAddDeadline={handleAddDeadline} 
                onToggleDeadline={handleToggleDeadline} 
