import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mic, Loader, X, Wand2, Sparkles, Square } from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { ParsedResponse } from '../types';

declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  start: () => void;
  stop: () => void;
  abort: () => void;
  onresult: (event: any) => void;
  onend: () => void;
  onerror: (event: any) => void;
}

interface VoiceModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (data: ParsedResponse) => void;
}

export const VoiceModal: React.FC<VoiceModalProps> = ({ isOpen, onClose, onConfirm }) => {
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [transcript, setTranscript] = useState('');

  const recognitionRef = useRef<SpeechRecognition | null>(null);
  // Track user intent to keep listening even if browser stops due to silence
  const shouldListenRef = useRef(false);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();

      if (recognitionRef.current) {
        // Enable continuous to allow user to pause without stopping
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;

        recognitionRef.current.onresult = (event: any) => {
          let finalTranscript = '';
          for (let i = 0; i < event.results.length; ++i) {
            finalTranscript += event.results[i][0].transcript;
          }
          setTranscript(finalTranscript);
        };

        recognitionRef.current.onend = () => {
          // If the user intends to keep listening (hasn't pressed stop), restart it
          if (shouldListenRef.current) {
            try {
               recognitionRef.current?.start();
            } catch (e) {
               console.error("Failed to restart speech recognition:", e);
               shouldListenRef.current = false;
               setIsListening(false);
            }
          } else {
            setIsListening(false);
          }
        };

        recognitionRef.current.onerror = (event: any) => {
            if (event.error === 'no-speech') {
                // Ignore no-speech error; onend will trigger and restart if shouldListenRef is true
                return;
            }
            console.error("Speech Recognition Error:", event.error);

            if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
               shouldListenRef.current = false;
               setIsListening(false);
            }
        };
      }
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      // User manually stopping
      shouldListenRef.current = false;
      recognitionRef.current?.stop();
      setIsListening(false);
    } else {
      // User starting
      setTranscript('');
      shouldListenRef.current = true;
      setIsListening(true);
      try {
        recognitionRef.current?.start();
      } catch (e) {
        console.error("Failed to start:", e);
        shouldListenRef.current = false;
        setIsListening(false);
      }
    }
  };

  const handleProcess = async () => {
    // Stop listening if still active
    if (isListening) {
        shouldListenRef.current = false;
        recognitionRef.current?.stop();
        setIsListening(false);
    }

    if (!transcript) return;
    setIsProcessing(true);
    try {
      const parsedData = await GeminiService.parseInputFromText(transcript);
      const hasContent = parsedData.habits.length > 0 || parsedData.todos.length > 0 || parsedData.deadlines.length > 0;

      if (hasContent) {
          onConfirm(parsedData);
          onClose();
          setTranscript('');
      } else {
          alert("Could not extract any items. Try saying 'Buy milk' or 'Run daily'.");
      }
    } catch (error) {
      console.error(error);
      alert("Failed to process with AI. Check console or API key.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          {/* Backdrop */}
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/80 backdrop-blur-xl"
            onClick={() => {
                shouldListenRef.current = false; // Ensure it stops if closed via backdrop
                if (isListening) recognitionRef.current?.stop();
                onClose();
            }}
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="w-full max-w-md bg-[#09090b] border border-white/10 rounded-3xl shadow-2xl relative z-10 overflow-hidden"
          >
            {/* Header */}
            <div className="p-6 flex justify-between items-center border-b border-white/5">
                <div className="flex items-center gap-2 text-white">
                   <Sparkles size={18} />
                   <h3 className="font-medium tracking-wide">Voice Assistant</h3>
                </div>
                <button 
                  onClick={() => {
                    shouldListenRef.current = false;
                    if (isListening) recognitionRef.current?.stop();
                    onClose();
                  }} 
                  className="text-zinc-500 hover:text-white transition-colors"
                >
                  <X size={20} />
                </button>
            </div>

            <div className="p-8 flex flex-col items-center">
              <div className="min-h-[120px] max-h-[200px] overflow-y-auto w-full text-center mb-8 flex items-center justify-center">
                {transcript ? (
                  <p className="text-white text-xl font-light leading-relaxed">"{transcript}"</p>
                ) : (
                  <div className="space-y-2 text-zinc-600 font-light">
                    <p>Try saying:</p>
                    <p className="text-zinc-500 italic">"Remind me to call Mom tomorrow"</p>
                    <p className="text-zinc-500 italic">"Read a book weekly"</p>
                    <p className="text-zinc-500 italic">"Project deadline next Friday"</p>
                  </div>
                )}
              </div>

              <button
                onClick={toggleListening}
                className={`
                  relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300
                  ${isListening 
                    ? 'bg-red-500 text-white shadow-[0_0_40px_rgba(239,68,68,0.4)]' 
                    : 'bg-white text-black hover:bg-zinc-200'}
                `}
              >
                {isListening ? (
                    <Square size={24} fill="currentColor" />
                ) : (
                    <Mic size={32} strokeWidth={1.5} />
                )}

                {isListening && (
                    <span className="absolute inset-0 rounded-full border border-red-500 animate-ping opacity-40"></span>
                )}
              </button>

              <p className="mt-6 text-xs text-zinc-500 uppercase tracking-widest font-medium">
                  {isListening ? 'Tap to Stop' : 'Tap to Speak'}
              </p>
            </div>

            <div className="p-4 bg-zinc-900/50 border-t border-white/5">
               <button 
                onClick={handleProcess}
                disabled={!transcript || isProcessing}
                className="w-full bg-white text-black py-4 rounded-xl font-bold flex items-center justify-center gap-3 disabled:opacity-20 disabled:cursor-not-allowed hover:bg-zinc-200 transition-colors"
               >
                 {isProcessing ? <Loader className="animate-spin" size={20}/> : <Wand2 size={20} />}
                 {isProcessing ? 'Processing...' : 'Create Items'}
               </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

export type Frequency = 'daily' | 'weekly' | 'monthly';

export interface Habit {
  id: string;
  title: string;
  frequency: Frequency;
  createdAt: string; // ISO Date string
  history: Record<string, boolean>; // key: YYYY-MM-DD (or YYYY-Wx or YYYY-MM), value: completed
}

export interface Task {
  id: string;
  title: string;
  completed: boolean;
  createdAt: string;
  isDeadlineRef?: boolean; // If true, this is a reference to a deadline
}

export interface Deadline {
  id: string;
  title: string;
  dueDate: string; // YYYY-MM-DD
  completed: boolean;
}

export interface DailyLog {
  id: string;
  date: string; // YYYY-MM-DD
  accomplishments: string;
  improvements: string;
}

export interface AppState {
  habits: Habit[];
  tasks: Task[];
  deadlines: Deadline[];
  dailyLogs: DailyLog[];
}

export type View = 'dashboard' | 'todo' | 'deadlines' | 'progress' | 'log';

// For Gemini Parsing
export interface ParsedResponse {
  habits: { title: string; frequency: Frequency }[];
  todos: { title: string }[];
  deadlines: { title: string; dueDate: string }[];
}

export interface ParsedDailyLog {
  accomplishments: string;
  improvements: string;
}

import { AppState } from '../types';

const STORAGE_KEY = 'neonflow_data_v2'; // Bump version for new schema

const DEFAULT_STATE: AppState = {
  habits: [],
  tasks: [],
  deadlines: [],
  dailyLogs: []
};

export const saveState = (state: AppState): void => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch (e) {
    console.error("Failed to save state", e);
  }
};

export const loadState = (): AppState => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    if (!data) return DEFAULT_STATE;

    const parsed = JSON.parse(data);

    // Migration helper: ensure dailyLogs exists
    if (!parsed.dailyLogs) parsed.dailyLogs = [];

    return parsed;
  } catch (e) {
    console.error("Failed to load state", e);
    return DEFAULT_STATE;
  }
};

export const clearState = (): void => {
  localStorage.removeItem(STORAGE_KEY);
};

import { GoogleGenAI, Type } from "@google/genai";
import { ParsedResponse, ParsedDailyLog, AppState } from "../types";

const apiKey = process.env.API_KEY;

const getAI = () => {
    if (!apiKey) throw new Error("API Key not found");
    return new GoogleGenAI({ apiKey });
};

const parseInputFromText = async (text: string): Promise<ParsedResponse> => {
  const ai = getAI();
  const today = new Date();
  const dateString = today.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  const systemInstruction = `
    You are an intelligent personal productivity assistant. 
    Analyze the user's natural language input and categorize it into Habits, To-Dos, and Deadlines.

    Current Date: ${dateString} (Use this to calculate dates for deadlines like "next Friday").

    CATEGORIES:
    1. HABITS: Recurring actions (e.g., "Run daily", "Read weekly", "Meditate"). 
       - Default frequency is 'daily' if not specified.
    2. TODOS: One-off tasks for today or generally (e.g., "Buy milk", "Call Mom", "Finish report").
    3. DEADLINES: Tasks with a specific future date/time (e.g., "Project due on Friday", "Submit taxes by April 15th").
       - 'dueDate' must be in YYYY-MM-DD format.

    Return a JSON object with three arrays: 'habits', 'todos', and 'deadlines'.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: text,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            habits: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  frequency: { type: Type.STRING, enum: ["daily", "weekly", "monthly"] }
                },
                required: ["title", "frequency"]
              }
            },
            todos: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING }
                },
                required: ["title"]
              }
            },
            deadlines: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  dueDate: { type: Type.STRING }
                },
                required: ["title", "dueDate"]
              }
            }
          },
          required: ["habits", "todos", "deadlines"]
        }
      }
    });

    const jsonText = response.text;
    if (!jsonText) return { habits: [], todos: [], deadlines: [] };

    return JSON.parse(jsonText) as ParsedResponse;
  } catch (error) {
    console.error("Gemini Parsing Error:", error);
    return { habits: [], todos: [], deadlines: [] };
  }
};

const parseDailyLog = async (text: string): Promise<ParsedDailyLog> => {
    const ai = getAI();
    const systemInstruction = `
        You are a journaling assistant. The user is dictating their day.
        Extract two things:
        1. Accomplishments: What went well, what they finished, wins.
        2. Improvements: What went wrong, what they need to focus on, struggles.

        Keep the tone natural and first-person.
        Return JSON.
    `;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: text,
            config: {
                systemInstruction,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        accomplishments: { type: Type.STRING },
                        improvements: { type: Type.STRING }
                    },
                    required: ["accomplishments", "improvements"]
                }
            }
        });

        const jsonText = response.text;
        if (!jsonText) return { accomplishments: '', improvements: '' };
        return JSON.parse(jsonText) as ParsedDailyLog;
    } catch (e) {
        console.error("Log Parsing Error", e);
        return { accomplishments: text, improvements: '' };
    }
};

const generateProgressSummary = async (state: AppState): Promise<string> => {
    const ai = getAI();

    // Prepare lightweight context
    const recentLogs = state.dailyLogs.slice(-7); // Last 7 logs
    const activeHabits = state.habits.filter(h => h.frequency === 'daily').map(h => {
        const historyCount = Object.values(h.history).filter(v => v).length;
        return `${h.title} (Total completions: ${historyCount})`;
    });
    const completedTasks = state.tasks.filter(t => t.completed).length;
    const openTasks = state.tasks.filter(t => !t.completed).length;

    const prompt = `
        Generate a motivational progress summary for the user.

        Data:
        - Daily Habits: ${activeHabits.join(', ')}
        - Tasks: ${completedTasks} completed, ${openTasks} pending.
        - Recent Journal Entries (Last 7 days):
          ${JSON.stringify(recentLogs.map(l => ({ date: l.date, wins: l.accomplishments, improve: l.improvements })))}

        Output Structure:
        1. **The Wins**: Celebrate their streaks and accomplishments.
        2. **Patterns**: Notice any recurring struggles from the logs.
        3. **Suggestion**: Give 1 actionable piece of advice for tomorrow.

        Keep it concise, punchy, and encouraging (Cyberpunk/Stoic vibe). Use Markdown formatting.
    `;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt
        });
        return response.text || "Unable to generate summary.";
    } catch (e) {
        console.error("Summary Generation Error", e);
        return "System Offline: Unable to analyze progress data.";
    }
};

export const GeminiService = {
  parseInputFromText,
  parseDailyLog,
  generateProgressSummary
};

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mic, Loader, X, Wand2, Sparkles, Square } from 'lucide-react';

declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  start: () => void;
  stop: () => void;
  abort: () => void;
  onresult: (event: any) => void;
  onend: () => void;
  onerror: (event: any) => void;
}

interface VoiceModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (result: any) => void;
  processingFunction: (text: string) => Promise<any>;
  title?: string;
  placeholder?: string;
}

export const VoiceModal: React.FC<VoiceModalProps> = ({ 
    isOpen, 
    onClose, 
    onConfirm, 
    processingFunction,
    title = "Voice Assistant",
    placeholder = "Try saying: 'Remind me to call Mom tomorrow'"
}) => {
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [transcript, setTranscript] = useState('');

  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const shouldListenRef = useRef(false);

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();

      if (recognitionRef.current) {
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;

        recognitionRef.current.onresult = (event: any) => {
          let finalTranscript = '';
          for (let i = 0; i < event.results.length; ++i) {
            finalTranscript += event.results[i][0].transcript;
          }
          setTranscript(finalTranscript);
        };

        recognitionRef.current.onend = () => {
          if (shouldListenRef.current) {
            try {
               recognitionRef.current?.start();
            } catch (e) {
               console.error("Restart fail", e);
               shouldListenRef.current = false;
               setIsListening(false);
            }
          } else {
            setIsListening(false);
          }
        };

        recognitionRef.current.onerror = (event: any) => {
            if (event.error === 'no-speech') return;
            if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
               shouldListenRef.current = false;
               setIsListening(false);
            }
        };
      }
    }
  }, []);

  const toggleListening = () => {
    if (isListening) {
      shouldListenRef.current = false;
      recognitionRef.current?.stop();
      setIsListening(false);
    } else {
      setTranscript('');
      shouldListenRef.current = true;
      setIsListening(true);
      try {
        recognitionRef.current?.start();
      } catch (e) {
        shouldListenRef.current = false;
        setIsListening(false);
      }
    }
  };

  const handleProcess = async () => {
    if (isListening) {
        shouldListenRef.current = false;
        recognitionRef.current?.stop();
        setIsListening(false);
    }

    if (!transcript) return;
    setIsProcessing(true);
    try {
      const result = await processingFunction(transcript);
      if (result) {
          onConfirm(result);
          onClose();
          setTranscript('');
      } else {
          alert("Could not process input.");
      }
    } catch (error) {
      console.error(error);
      alert("AI Processing Failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/80 backdrop-blur-xl"
            onClick={() => {
                shouldListenRef.current = false;
                if (isListening) recognitionRef.current?.stop();
                onClose();
            }}
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="w-full max-w-md bg-[#09090b] border border-white/10 rounded-3xl shadow-2xl relative z-10 overflow-hidden"
          >
            <div className="p-6 flex justify-between items-center border-b border-white/5">
                <div className="flex items-center gap-2 text-white">
                   <Sparkles size={18} />
                   <h3 className="font-medium tracking-wide">{title}</h3>
                </div>
                <button 
                  onClick={() => {
                    shouldListenRef.current = false;
                    if (isListening) recognitionRef.current?.stop();
                    onClose();
                  }} 
                  className="text-zinc-500 hover:text-white transition-colors"
                >
                  <X size={20} />
                </button>
            </div>

            <div className="p-8 flex flex-col items-center">
              <div className="min-h-[120px] max-h-[200px] overflow-y-auto w-full text-center mb-8 flex items-center justify-center">
                {transcript ? (
                  <p className="text-white text-xl font-light leading-relaxed">"{transcript}"</p>
                ) : (
                  <div className="text-zinc-500 font-light italic text-center px-4">
                    {placeholder}
                  </div>
                )}
              </div>

              <button
                onClick={toggleListening}
                className={`
                  relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300
                  ${isListening 
                    ? 'bg-red-500 text-white shadow-[0_0_40px_rgba(239,68,68,0.4)]' 
                    : 'bg-white text-black hover:bg-zinc-200'}
                `}
              >
                {isListening ? <Square size={24} fill="currentColor" /> : <Mic size={32} strokeWidth={1.5} />}
                {isListening && (
                    <span className="absolute inset-0 rounded-full border border-red-500 animate-ping opacity-40"></span>
                )}
              </button>

              <p className="mt-6 text-xs text-zinc-500 uppercase tracking-widest font-medium">
                  {isListening ? 'Tap to Stop' : 'Tap to Speak'}
              </p>
            </div>

            <div className="p-4 bg-zinc-900/50 border-t border-white/5">
               <button 
                onClick={handleProcess}
                disabled={!transcript || isProcessing}
                className="w-full bg-white text-black py-4 rounded-xl font-bold flex items-center justify-center gap-3 disabled:opacity-20 disabled:cursor-not-allowed hover:bg-zinc-200 transition-colors"
               >
                 {isProcessing ? <Loader className="animate-spin" size={20}/> : <Wand2 size={20} />}
                 {isProcessing ? 'Processing...' : 'Process'}
               </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};

