    const newDate = new Date(currentDate);
    newDate.setDate(newDate.getDate() + days);
    setCurrentDate(newDate);
  };

  const handleSave = () => {
    const log: DailyLog = {
      id: dateKey,
      date: dateKey,
      accomplishments,
      improvements
    };
    onSaveLog(log);
    setShowSaved(true);
    setTimeout(() => setShowSaved(false), 2000);
