      {/* Floating Navigation Dock */}
      <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 z-50 w-full max-w-sm px-4">
        <nav className="glass-nav rounded-2xl p-2 flex justify-between items-center shadow-2xl border border-white/10">
          <button 
            onClick={() => setCurrentView('dashboard')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'dashboard' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <LayoutDashboard size={20} strokeWidth={1.5} />
            <span className="text-[9px] font-medium tracking-wide">Habits</span>
          </button>

          <button 
            onClick={() => setCurrentView('todo')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'todo' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <CheckSquare size={20} strokeWidth={1.5} />
            <span className="text-[9px] font-medium tracking-wide">To-Do</span>
          </button>

          <button 
            onClick={() => setCurrentView('deadlines')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'deadlines' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <Clock size={20} strokeWidth={1.5} />
            <span className="text-[9px] font-medium tracking-wide">Due</span>
          </button>

          <button 
            onClick={() => setCurrentView('progress')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'progress' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <BarChart2 size={20} strokeWidth={1.5} />
            <span className="text-[9px] font-medium tracking-wide">Progress</span>
          </button>

          <button 
             onClick={() => setCurrentView('log')}
            className={`flex-1 flex flex-col items-center gap-1 py-3 rounded-xl transition-all ${currentView === 'log' ? 'bg-white/10 text-white' : 'text-zinc-500 hover:text-zinc-300'}`}
          >
            <BookOpen size={20} strokeWidth={1.5} />
            <span className="text-[9px] font-medium tracking-wide">Log</span>
          </button>
        </nav>
      </div>

      <VoiceModal 
        isOpen={isVoiceModalOpen} 
        onClose={() => setIsVoiceModalOpen(false)} 
        onConfirm={handleAIResponse}
        processingFunction={GeminiService.parseInputFromText}
      />

      <ManualHabitModal
        isOpen={isManualModalOpen}
        onClose={() => setIsManualModalOpen(false)}
        onSave={handleSaveManualHabit}
        editHabit={editingHabit}
      />

    </div>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Mic, Loader, X, Wand2, Sparkles, Square } from 'lucide-react';

declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  start: () => void;
  stop: () => void;
  abort: () => void;
  onresult: (event: any) => void;
  onend: () => void;
  onerror: (event: any) => void;
}

interface VoiceModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: (result: any) => void;
  processingFunction: (text: string) => Promise<any>;
  title?: string;
  placeholder?: string;
}

export const VoiceModal: React.FC<VoiceModalProps> = ({ 
    isOpen, 
    onClose, 
    onConfirm, 
    processingFunction,
    title = "Voice Assistant",
    placeholder = "Try saying: 'Remind me to call Mom tomorrow'"
}) => {
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [interimTranscript, setInterimTranscript] = useState('');

  const recognitionRef = useRef<SpeechRecognition | null>(null);
  const shouldListenRef = useRef(false);
  const finalTranscriptRef = useRef(''); // Use ref to avoid state-lag resets during long speech

  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();

      if (recognitionRef.current) {
        recognitionRef.current.continuous = true;
        recognitionRef.current.interimResults = true;

        recognitionRef.current.onresult = (event: any) => {
          let interim = '';
          for (let i = event.resultIndex; i < event.results.length; ++i) {
            if (event.results[i].isFinal) {
              finalTranscriptRef.current += event.results[i][0].transcript;
            } else {
              interim += event.results[i][0].transcript;
            }
          }
          setTranscript(finalTranscriptRef.current);
          setInterimTranscript(interim);
        };

        recognitionRef.current.onend = () => {
          // If the browser engine stops but the user hasn't pressed 'Stop', restart immediately
          if (shouldListenRef.current) {
            try {
               recognitionRef.current?.start();
            } catch (e) {
               console.error("Auto-restart failed:", e);
               // If it really fails to restart, sync UI state
               if (finalTranscriptRef.current === '') setIsListening(false);
            }
          } else {
            setIsListening(false);
          }
        };

        recognitionRef.current.onerror = (event: any) => {
            // "no-speech" is common and handled by the onend restart logic
            if (event.error === 'no-speech') return;

            console.error("Speech Recognition Error:", event.error);
            if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
               shouldListenRef.current = false;
               setIsListening(false);
               alert("Microphone access denied or service unavailable.");
            }
        };
      }
    }

    return () => {
      if (recognitionRef.current) {
        recognitionRef.current.stop();
      }
    };
  }, []);

  const toggleListening = () => {
    if (isListening) {
      shouldListenRef.current = false;
      recognitionRef.current?.stop();
      setIsListening(false);
      setInterimTranscript('');
    } else {
      finalTranscriptRef.current = '';
      setTranscript('');
      setInterimTranscript('');
      shouldListenRef.current = true;
      setIsListening(true);
      try {
        recognitionRef.current?.start();
      } catch (e) {
        console.error("Start failed:", e);
        shouldListenRef.current = false;
        setIsListening(false);
      }
    }
  };

  const handleProcess = async () => {
    if (isListening) {
        shouldListenRef.current = false;
        recognitionRef.current?.stop();
        setIsListening(false);
    }

    const fullText = (transcript + ' ' + interimTranscript).trim();
    if (!fullText) return;

    setIsProcessing(true);
    try {
      const result = await processingFunction(fullText);
      if (result) {
          onConfirm(result);
          onClose();
          // Reset internal refs/state after success
          finalTranscriptRef.current = '';
          setTranscript('');
          setInterimTranscript('');
      } else {
          alert("Could not process input.");
      }
    } catch (error) {
      console.error(error);
      alert("AI Processing Failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <motion.div 
            initial={{ opacity: 0 }} 
            animate={{ opacity: 1 }} 
            exit={{ opacity: 0 }}
            className="absolute inset-0 bg-black/80 backdrop-blur-xl"
            onClick={() => {
                shouldListenRef.current = false;
                if (isListening) recognitionRef.current?.stop();
                onClose();
            }}
          />

          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="w-full max-w-md bg-[#09090b] border border-white/10 rounded-3xl shadow-2xl relative z-10 overflow-hidden"
          >
            <div className="p-6 flex justify-between items-center border-b border-white/5">
                <div className="flex items-center gap-2 text-white">
                   <Sparkles size={18} />
                   <h3 className="font-medium tracking-wide">{title}</h3>
                </div>
                <button 
                  onClick={() => {
                    shouldListenRef.current = false;
                    if (isListening) recognitionRef.current?.stop();
                    onClose();
                  }} 
                  className="text-zinc-500 hover:text-white transition-colors"
                >
                  <X size={20} />
                </button>
            </div>

            <div className="p-8 flex flex-col items-center">
              <div className="min-h-[140px] max-h-[250px] overflow-y-auto w-full text-center mb-8 flex flex-col items-center justify-center">
                {transcript || interimTranscript ? (
                  <div className="space-y-2">
                    <p className="text-white text-xl font-light leading-relaxed">
                      {transcript}
                      <span className="text-zinc-500">{interimTranscript}</span>
                    </p>
                  </div>
                ) : (
                  <div className="text-zinc-500 font-light italic text-center px-4">
                    {placeholder}
                  </div>
                )}
              </div>

              <button
                onClick={toggleListening}
                className={`
                  relative w-20 h-20 rounded-full flex items-center justify-center transition-all duration-300
                  ${isListening 
                    ? 'bg-red-500 text-white shadow-[0_0_40px_rgba(239,68,68,0.4)]' 
                    : 'bg-white text-black hover:bg-zinc-200'}
                `}
              >
                {isListening ? <Square size={24} fill="currentColor" /> : <Mic size={32} strokeWidth={1.5} />}

                {isListening && (
                    <>
                      <span className="absolute inset-0 rounded-full border border-red-500 animate-ping opacity-40"></span>
                      <span className="absolute -inset-2 rounded-full border border-red-500/20 animate-pulse"></span>
                    </>
                )}
              </button>

              <p className="mt-6 text-xs text-zinc-500 uppercase tracking-widest font-medium">
                  {isListening ? 'Tap to Pause' : 'Tap to Start'}
              </p>
            </div>

            <div className="p-4 bg-zinc-900/50 border-t border-white/5">
               <button 
                onClick={handleProcess}
                disabled={(!transcript && !interimTranscript) || isProcessing}
                className="w-full bg-white text-black py-4 rounded-xl font-bold flex items-center justify-center gap-3 disabled:opacity-20 disabled:cursor-not-allowed hover:bg-zinc-200 transition-colors shadow-lg"
               >
                 {isProcessing ? <Loader className="animate-spin" size={20}/> : <Wand2 size={20} />}
                 {isProcessing ? 'Thinking...' : 'Process Speech'}
               </button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
};
